+            Some(String::from(
+                "defined host behavior diverged from Rust implementation",
+            ))
+        } else {
+            None
+        };
+
+        return Ok(DifferentialExecution {
+            host_output,
+            impl_output,
+            host_parity,
+            note,
+        });
+    }
